            // Example: Transform or enrich the document
            const processedDoc = {
                id: doc.id,
                originalData: doc,
                processedTimestamp: new Date().toISOString(),
                status: 'processed',
                // Add any new fields or modifications here
                summary: `Document ${doc.id} processed successfully in ${workTimeMs}ms.`
            };
            processedResults.push(processedDoc);

            processedCount++;
            if (processedCount % 10 === 0) { // Log progress every 10 documents
                context.log(`Processed ${processedCount}/${totalDocuments} documents...`);
            }

            // Optional: Implement a checkpointing mechanism for very long-running tasks
